import React, { useState } from 'react';
import { Search } from 'lucide-react';

import imagenHome from '../imagenes/Home';

const Home = ({ isLoggedIn, userRole }) => {
  const [busqueda, setBusqueda] = useState('');

  // 1. LÓGICA: Si es VENDEDOR, ve una bienvenida de gestión (sin buscador de compras)
  if (isLoggedIn && userRole === 'vendedor') {
    return (
      <div style={containerVendedor}>
        <div style={cardBienvenida}>
          <h1 style={{ color: '#1e293b', fontSize: '2.5rem' }}>Panel de Negocios</h1>
          <p style={{ color: '#64748b', fontSize: '1.2rem' }}>
            Bienvenido. Desde aquí puedes gestionar tus sucursales y publicar ofertas.
          </p>
          <button 
            style={btnGestion} 
            onClick={() => window.location.href = '/dashboard'}
          >
            Ir a Mis Locales
          </button>
        </div>
      </div>
    );
  }

  // 2. LÓGICA: Si NO está registrado o es CLIENTE, ve el Home "Bello" con buscador
  return (
    <div style={homeWrapper}>
      {/* IMAGEN DE FONDO DE SUPERMERCADO / SHOPPING */}
      <div style={heroBackground}>
        <div style={overlay}>
          <div style={contentCenter}>
            <h1 style={mainTitle}>
              Encontrá las mejores ofertas <br/> 
              <span style={{ color: '#e67e22' }}>en un solo lugar</span>
            </h1>
            
            {/* BARRA DE BÚSQUEDA CENTRAL */}
            <div style={searchWrapper}>
              <div style={searchBar}>
                <Search size={22} color="#94a3b8" />
                <input 
                  type="text" 
                  placeholder="¿Qué producto estás buscando?" 
                  style={inputStyle}
                  value={busqueda}
                  onChange={(e) => setBusqueda(e.target.value)}
                />
                <button style={btnSearch}>Buscar</button>
              </div>
            </div>
          </div>
        </div>
      </div>
      
      {/* SE ELIMINARON FILTROS, ZONAS Y OFERTAS DE ESTA PARTE */}
    </div>
  );
};

/* --- ESTILOS PARA LOGRAR EL DISEÑO QUE BUSCAS --- */

const homeWrapper = {
  width: '100%',
  height: 'calc(100vh - 75px)', // Ajuste para que ocupe el resto de la pantalla tras el header
  overflow: 'hidden'
};

const heroBackground = {
  width: '100%',
  height: '100%',
  // Imagen de supermercado de alta calidad
  backgroundSize: 'cover', backgroundImage: 'url(imagenHome)',
  backgroundPosition: 'center',
  position: 'relative'
};

const overlay = {
  position: 'absolute',
  inset: 0,
  backgroundColor: 'rgba(0, 0, 0, 0.45)', // Oscurece un poco la imagen para que el texto resalte
  display: 'flex',
  justifyContent: 'center',
  alignItems: 'center'
};

const contentCenter = {
  textAlign: 'center',
  width: '100%',
  maxWidth: '800px',
  padding: '0 20px'
};

const mainTitle = {
  color: 'white',
  fontSize: '4rem',
  fontWeight: '900',
  marginBottom: '40px',
  lineHeight: '1.1',
  textShadow: '2px 2px 10px rgba(0,0,0,0.5)'
};

const searchWrapper = {
  display: 'flex',
  justifyContent: 'center',
  width: '100%'
};

const searchBar = {
  display: 'flex',
  alignItems: 'center',
  background: 'white',
  width: '100%',
  maxWidth: '700px',
  padding: '10px 10px 10px 25px',
  borderRadius: '50px',
  boxShadow: '0 15px 35px rgba(0,0,0,0.3)'
};

const inputStyle = {
  flex: 1,
  border: 'none',
  outline: 'none',
  fontSize: '1.2rem',
  padding: '15px',
  color: '#334155'
};

const btnSearch = {
  background: '#e67e22',
  color: 'white',
  border: 'none',
  padding: '15px 40px',
  borderRadius: '40px',
  fontWeight: 'bold',
  fontSize: '1rem',
  cursor: 'pointer',
  transition: '0.3s'
};

// Estilos para la vista de Vendedor
const containerVendedor = { 
  height: '100%', display: 'flex', justifyContent: 'center', alignItems: 'center', background: '#f1f5f9' 
};
const cardBienvenida = {
  background: 'white', padding: '60px', borderRadius: '25px', textAlign: 'center', boxShadow: '0 4px 20px rgba(0,0,0,0.05)'
};
const btnGestion = {
  marginTop: '25px', padding: '15px 40px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold'
};

export default Home;
